class Node:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

class BinaryTree:
    def __init__(self):
        self.root = None

    def calculate_depth(self):
        return self._get_depth_recursive(self.root)

    def _get_depth_recursive(self, node):
        if node is None:
            return -1

        left_subtree_depth = self._get_depth_recursive(node.left)
        right_subtree_depth = self._get_depth_recursive(node.right)

        return 1 + max(left_subtree_depth, right_subtree_depth)
